export default class MultiRoute extends HTMLElement{constructor(props){super(),this.props=props,this.renderedComponents=new Map}init(){if(!this.props.routes||!Array.isArray(this.props.routes))return slice.logger.logError("MultiRoute","No valid routes array provided in props."),void 0}matchRoute(t){t=t.length>1?t.replace(/\/+$/,""):t;const e=t.toLowerCase(),s=this.props.routes.find(t=>(t.path.length>1?t.path.replace(/\/+$/,""):t.path).toLowerCase()===e);if(s)return{route:s,params:{}};for(const e of this.props.routes)if(e.path.includes("${")){const{regex:s,paramNames:i}=this.compilePathPattern(e.path),o=t.match(s);if(o){const t={};return i.forEach((e,s)=>{t[e]=o[s+1]}),{route:e,params:t}}}return{route:null,params:{}}}compilePathPattern(t){const e=[],s="^"+t.replace(/\$\{([^}]+)\}/g,(t,s)=>(e.push(s),"([^/]+)"))+"$";return{regex:new RegExp(s,"i"),paramNames:e}}async render(){const t=window.location.pathname,{route:e,params:s}=this.matchRoute(t);if(e){const{component:i,metadata:o}=e;if(this.renderedComponents.has(i)){const t=this.renderedComponents.get(i);this.innerHTML="",t.props&&(t.props={...t.props,params:s,metadata:o||{}}),t.update&&await t.update(),this.appendChild(t)}else{if(!slice.controller.componentCategories.has(i))return slice.logger.logError(`${this.t}`,`Component ${i} not found`),void 0;const t=await slice.build(i,{params:s,metadata:o||{}});this.innerHTML="",this.appendChild(t),this.renderedComponents.set(i,t)}this.dispatchEvent(new CustomEvent("route-rendered",{bubbles:!0,detail:{component:i,path:t,params:s,metadata:o||{}}}))}else this.innerHTML=""}async renderIfCurrentRoute(){const t=window.location.pathname,{route:e}=this.matchRoute(t);return!!e&&(await this.render(),!0)}removeComponent(){const t=window.location.pathname,{route:e}=this.matchRoute(t);if(e){const{component:t}=e;this.renderedComponents.delete(t),this.innerHTML=""}}destroy(){this.renderedComponents.clear(),this.innerHTML=""}}customElements.define("slice-multi-route",MultiRoute);